namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the app!"),
            CreateNotification("Your profile has been set up."),
            CreateNotification("You have 3 pending invitations."),
        });
    }

    /// <summary>Returns all notifications available at the time of the call.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications created after the given timestamp.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        lock (_lock)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Timestamp > since).ToList());
        }
    }

    /// <summary>Simulates an external system producing a new notification.</summary>
    public void SimulateIncoming()
    {
        string[] templates =
        [
            "New comment on your post.",
            "Someone liked your photo.",
            "Deployment succeeded.",
            "Disk usage alert: 85 %.",
            "Weekly report is ready.",
            "New follower joined.",
        ];

        lock (_lock)
        {
            var msg = templates[Random.Shared.Next(templates.Length)];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService Svc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    protected override async Task OnInitializedAsync()
    {
        // Restore from prerender state if available; otherwise fetch once.
        PersistedNotifications ??= await Svc.GetNotificationsAsync();
        notifications = PersistedNotifications;
        _lastCheck = notifications.Count > 0
            ? notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate an external notification arriving.
                Svc.SimulateIncoming();

                var newer = await Svc.GetNotificationsSinceAsync(_lastCheck);
                if (newer.Count > 0)
                {
                    notifications.AddRange(newer);
                    _lastCheck = newer.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

